<?php
namespace App\Modules\Hr\Workforce\Models; use App\Modules\Hr\Core\Traits\BelongsToLegalEntity; use App\Modules\Hr\Organization\Models\HrDepartment; use App\Modules\Hr\Organization\Models\HrPosition; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo;
class HrWorkforcePlanLine extends Model { use BelongsToLegalEntity; protected $fillable=['legal_entity_id','workforce_plan_id','department_id','position_id','planned_fte','planned_monthly_cost_encrypted','actual_fte_snapshot','actual_monthly_cost_encrypted','notes']; protected $hidden=['planned_monthly_cost_encrypted','actual_monthly_cost_encrypted']; protected function casts():array{return['planned_fte'=>'decimal:2','actual_fte_snapshot'=>'decimal:2','planned_monthly_cost_encrypted'=>'encrypted','actual_monthly_cost_encrypted'=>'encrypted'];} public function plan():BelongsTo{return$this->belongsTo(HrWorkforcePlan::class,'workforce_plan_id');} public function department():BelongsTo{return$this->belongsTo(HrDepartment::class);} public function position():BelongsTo{return$this->belongsTo(HrPosition::class);} public function plannedCost():float{return(float)$this->planned_monthly_cost_encrypted;} public function actualCost():?float{return$this->actual_monthly_cost_encrypted===null?null:(float)$this->actual_monthly_cost_encrypted;} }
